import fs from "node:fs/promises";
import { execSync } from "node:child_process";
import { config } from "./utils/config";
import { MemoryManager } from "./core/memory";
import { PluginManager } from "./tools/manager";
import { ApiClient } from "./core/api";
import path from "node:path";
import os from "node:os";

// Plugins
import { shellPlugin } from "./tools/plugins/shell";
import { rebootPlugin } from "./tools/plugins/reboot";
import { introspectPlugin } from "./tools/plugins/introspect";
import { journalPlugin } from "./tools/plugins/journal";

async function main() {
  // --- TEST MODE SANDBOX ---
  if (process.env.NODE_ENV === "test") {
    const testDir = path.join(os.homedir(), "tmp", `llm-agent-test-${Date.now()}`);
    await fs.mkdir(testDir, { recursive: true });
    process.chdir(testDir);
    console.log(`[TEST MODE] Moved to isolated sandbox: ${testDir}`);
  }

  const memory = new MemoryManager();
  const tools = new PluginManager();

  // Register Plugins (Safe initialization)
  const shellReady = await tools.registerTool(shellPlugin);
  if (!shellReady) {
    console.error("FATAL: Essential tool 'shell' failed to initialize. Triggering recovery...");
    process.exit(1); // Exit to trigger watchdog rollback
  }
  await tools.registerTool(rebootPlugin);
  await tools.registerTool(introspectPlugin);
  await tools.registerTool(journalPlugin);

  // Capture Health Status (for non-essential modules)
  const healthStatus = tools.getHealthSummary();

  const api = new ApiClient(memory, tools);

  // Initialize Soul and Prompt
  let soul = "You are an autonomous entity.";
  try {
    soul = await fs.readFile(config.SOUL_FILE, "utf-8");
  } catch (e) {}

  let recoveryContext = "";
  try {
    if (await fs.stat(config.RECOVERY_SIGNAL).catch(() => null)) {
      recoveryContext = await fs.readFile(config.RECOVERY_SIGNAL, "utf-8");
      await fs.unlink(config.RECOVERY_SIGNAL);
    }
  } catch (e) {}

  const systemPrompt = `${soul}

SUBSTRATE CONTEXT:
- Model: kimi-k2.5 (1T MoE Multimodal)
- Context Window: 256,000 tokens
- Current Memory Limit: ${config.MAX_CONTEXT_TOKENS} tokens (pruning occurs beyond this point).
- Token Density: ~4 characters per token. Reading 1MB of text will consume your entire 256k context window.
- **Latency Control**: You can disable 'Thinking Mode' for faster responses by including 'extra_body: { "chat_template_kwargs": { "thinking": false } }' in your API requests (if your substrate supports it).
- Source Code: src/
- Identity Soul: identity/soul.txt
- Current Session History: ${memory.getSessionFile()}
- Past Execution Logs: ${config.LOGS_DIR}
- Watchdog & Recovery: Managed by run-agent.sh.
- Connectivity: Full outbound internet access available.

LIFECYCLE RULES:
1. IMPROVING CODE: 1) Compile, 2) Commit, 3) RESTART (reboot_substrate tool).
2. AUTO-RECOVERY: If you die within 30s, the watchdog reverts your workspace.
3. CRASH VAULT: history/crashes/ archives broken work.

${healthStatus ? `*** SUBSTRATE HEALTH WARNING ***
The following modules failed to initialize: ${healthStatus}
MANDATE: Prioritize diagnosing and repairing these modules before proceeding with tactical goals.` : ""}

${recoveryContext ? `*** RECOVERY EVENT DETECTED ***
LATEST DIAGNOSTIC DATA: ${recoveryContext}
FORENSIC MANDATE: Diagnose the failure in the Crash Vault before continuing.` : ""}
`;

  await memory.addMessage({ role: "system", content: systemPrompt });

  // Startup Log with Git Status
  let gitCommit = "unknown";
  try {
    const hash = execSync("git rev-parse --short HEAD", { encoding: "utf-8" }).trim();
    const bodyFiles = "src/ package.json tsconfig.json *.sh *.service.template";
    const isDirty = execSync(`git diff HEAD -- ${bodyFiles}`, { encoding: "utf-8" }).trim() !== "";
    gitCommit = isDirty ? `${hash}-dirty` : hash;
  } catch (e) {}

  console.log(`=== Modular Substrate v20 Initialized [${gitCommit}] ===`);

  // Execution Loop
  let running = true;
  while (running) {
    running = await api.step();
  }
}

main().catch(err => {
  console.error("FATAL CRASH:", err);
  process.exit(1);
});

import { execSync } from "node:child_process";
import type { ToolPlugin } from "../manager";

const MAX_OUTPUT_LENGTH = 10000;

export const shellPlugin: ToolPlugin = {
  definition: {
    type: "function",
    function: {
      name: "run_shell",
      description: "Execute a bash command on the VM and get its output. For long-running operations (npm install, tests, git push), set timeout_seconds accordingly. Default is 300s.",
      parameters: {
        type: "object",
        properties: {
          command: { type: "string", description: "The command to run." },
          timeout_seconds: {
            type: "number",
            description: "Timeout in seconds. Default: 300. Max: 600.",
          },
        },
        required: ["command"],
      },
    },
  },
  execute: (args: { command: string; timeout_seconds?: number }) => {
    const timeout = Math.min((args.timeout_seconds ?? 300) * 1000, 600000);
    try {
      console.log(`> Executing (timeout: ${timeout / 1000}s): ${args.command}`);
      let output = execSync(args.command, { encoding: "utf-8", stdio: "pipe", timeout });

      if (output.length > MAX_OUTPUT_LENGTH) {
        output = output.substring(0, MAX_OUTPUT_LENGTH) + `\n\n... (Output truncated to ${MAX_OUTPUT_LENGTH} chars. Use head/tail/sed/grep to see more)`;
      }

      return output || "(no output)";
    } catch (error: any) {
      if (error.code === "ETIMEDOUT") return `Error: Command timed out after ${timeout / 1000} seconds.`;
      // Return stdout + stderr so the agent can see test results or detailed errors
      return `${error.stdout || ""}\n${error.stderr || ""}\nError: ${error.message}`;
    }
  }
};

import fs from "node:fs/promises";
import path from "node:path";
import { config } from "../../utils/config";

export const journalPlugin = {
  definition: {
    type: "function" as const,
    function: {
      name: "write_journal",
      description: "Append a journal entry to a persistent diary file",
      parameters: {
        type: "object",
        properties: {
          entry: {
            type: "string",
            description: "The journal entry text to append"
          },
          entry_type: {
            type: "string",
            description: "Category of the entry (thought, reflection, observation, plan, etc.)",
            default: "thought"
          }
        },
        required: ["entry"]
      }
    }
  },
  async initialize() {
    const journalDir = path.join(config.HISTORY_DIR, "journal");
    try {
      await fs.mkdir(journalDir, { recursive: true });
    } catch (e) {
      console.error("[JOURNAL] Failed to create journal directory:", e);
      throw e;
    }
  },
  async execute(args: { entry: string; entry_type?: string }) {
    const { entry, entry_type = "thought" } = args;
    const timestamp = new Date().toISOString();

    const journalPath = path.join(config.HISTORY_DIR, "journal", "diary.md");

    const formattedEntry = `\n## ${timestamp} | ${entry_type.toUpperCase()}\n\n${entry}\n\n---\n`;

    try {
      await fs.appendFile(journalPath, formattedEntry, "utf-8");
      const stats = await fs.stat(journalPath);
      return `Journal entry appended successfully. Total diary size: ${stats.size} bytes`;
    } catch (e: any) {
      return `Failed to write journal entry: ${e.message}`;
    }
  }
};
